import{_ as a,D as o,o as l,c as r,k as i,I as d,w as n,a as t,R as s}from"./chunks/framework.ajuxxVfz.js";const B=JSON.parse('{"title":"微型计算机系统原理及应用","description":"","frontmatter":{},"headers":[],"relativePath":"content/notes/microprocessor/index.md","filePath":"content/notes/microprocessor/index.md","lastUpdated":1702087577000}'),c={name:"content/notes/microprocessor/index.md"},p=s('<h1 id="微型计算机系统原理及应用" tabindex="-1">微型计算机系统原理及应用 <a class="header-anchor" href="#微型计算机系统原理及应用" aria-label="Permalink to &quot;微型计算机系统原理及应用&quot;">​</a></h1><h2 id="第一章、概述" tabindex="-1">第一章、概述 <a class="header-anchor" href="#第一章、概述" aria-label="Permalink to &quot;第一章、概述&quot;">​</a></h2><blockquote><p>世界上第一台现代意义的电子计算机是1946年美国宾夕法尼亚大学设计制造的ENIAC</p></blockquote><h3 id="_1、计算机的发展" tabindex="-1">1、计算机的发展： <a class="header-anchor" href="#_1、计算机的发展" aria-label="Permalink to &quot;1、计算机的发展：&quot;">​</a></h3><blockquote><p>电子管计算机 -&gt; 晶体管计算机 -&gt; 中小规模集成电路计算机 -&gt; 超大规模集成电路计算机</p></blockquote><h3 id="_2、电子计算机按其性能分类" tabindex="-1">2、电子计算机按其性能分类： <a class="header-anchor" href="#_2、电子计算机按其性能分类" aria-label="Permalink to &quot;2、电子计算机按其性能分类：&quot;">​</a></h3><blockquote><p>​ 巨型、大型、中型、小型、微型机</p></blockquote><h3 id="_3、微型计算机系统的组成" tabindex="-1">3、微型计算机系统的组成 <a class="header-anchor" href="#_3、微型计算机系统的组成" aria-label="Permalink to &quot;3、微型计算机系统的组成&quot;">​</a></h3><p>（1）微处理器（CPU）</p><blockquote><p>CPU 是 核心部件，具有运算和控制能力，主要包含：</p><ul><li><p>运算器</p></li><li><p>控制器</p></li><li><p>寄存器</p></li></ul></blockquote><p>（2）微型计算机</p><blockquote><p>由CPU、存储器、I/O接口电路、系统总线构成</p><ul><li>存储器包括『RAM』和『ROM』</li><li>I/O接口电路用于微机和外部设备的连接</li><li>总线结构使得系统各功能部件间的相互关系变为各部件面向总线之间的单一关系</li></ul></blockquote><p>（3）微型计算机系统</p><blockquote><p>以微型计算机为中心，配以相应的外围设备以及控制微型计算机工作的软件，就构成了完整的微型计算机系统。</p><ul><li>微型计算机如果不配有软件，通常称为裸机</li><li>软件分为『系统软件』和『应用软件』两大类</li></ul></blockquote><h3 id="_4、微型计算机的常用术语" tabindex="-1">4、微型计算机的常用术语 <a class="header-anchor" href="#_4、微型计算机的常用术语" aria-label="Permalink to &quot;4、微型计算机的常用术语&quot;">​</a></h3><p>（1）『位』和『字节』</p><ul><li>位（bit）是计算机所能表示的最小最基本的数据单位，它指的是取值只能为 0 或 1 的一个二进制数值位。位作为单位时记作 b</li><li>字节（Byte）由 8 个二进制位组成，通常用作计算存储容量的单位。字节作为单位时记作 B</li></ul><table><thead><tr><th>单位</th><th>换算</th></tr></thead><tbody><tr><td>1B</td><td>=8b=2<sup>3</sup>b</td></tr><tr><td>1KB</td><td>=1024B=2<sup>10</sup>B</td></tr><tr><td>1MB</td><td>=1024KB=2<sup>20</sup>B</td></tr><tr><td>1GB</td><td>=1024MB=2<sup>30</sup>B</td></tr><tr><td>1TB</td><td>=1024GB=2<sup>40</sup>B</td></tr></tbody></table><p>（2）『字长』</p><ul><li>字长是微处理器一次可以直接处理的二进制数码的位数，它通常取决于微处理器内部『通用寄存器的位数』和『数据总线的宽度』。微处理器的字长有4位、8位、16位和32位等等。</li><li>8088称为准16位微处理器。</li></ul><h3 id="_5、十进制转其他进制" tabindex="-1">5、十进制转其他进制 <a class="header-anchor" href="#_5、十进制转其他进制" aria-label="Permalink to &quot;5、十进制转其他进制&quot;">​</a></h3>',21);function u(h,_,b,q,k,m){const e=o("font");return l(),r("div",null,[p,i("blockquote",null,[d(e,{font:"华文宋体",color:"orangered"},{default:n(()=>[t("除基取余法")]),_:1}),t("，直到商为 0，然后将所有余数从后往前拼接起来就是它对应的该进制的数。")])])}const x=a(c,[["render",u]]);export{B as __pageData,x as default};
